  if (viewport === "desktop") {
    expect(summaryBox.x).toBeGreaterThan(toggleBox.x + toggleBox.width - 24);
  } else {
    expect(summaryBox.y).toBeGreaterThan(toggleBox.y + toggleBox.height - 8);
